import React from "react";
import API from "../services/api";

function TaskList({ tasks, fetchTasks, setEditTask }) {

  const deleteTask = async (id) => {
    if (!window.confirm("Delete this task?")) return;

    await API.delete(`/tasks/${id}`);
    fetchTasks();
  };

  return (
    <div className="task-list">

      {tasks.length === 0 ? (
        <p>No Tasks Found</p>
      ) : (
        tasks.map((task) => (
          <div
            key={task._id}
            style={{
              border: "1px solid gray",
              marginTop: "15px",
              padding: "15px",
            }}
          >
            <h3>{task.title}</h3>

            <p>{task.description}</p>

            <p>
              <h2
                style={{
                borderBottom:"4px solid #6d28d9",
                paddingBottom:"10px",
                marginBottom:"20px",
                fontSize:"32px",
                fontWeight:"bold"
                }}
            >
            📋 Task List
            </h2>
          <span
              className={`status ${
              task.status==="Pending"
              ?"pending"
              :task.status==="In Progress"
              ?"progress"
              :"completed"
              }`}
            >
            {task.status}
          </span>
            </p>
            <p>
              <b>Due Date:</b>{" "}
              {task.dueDate
              ? new Date(task.dueDate).toLocaleDateString()
              : "Not Set"}
            </p>
            <button onClick={() => setEditTask(task)}>
              Edit
            </button>

            {" "}

            <button
              onClick={() => deleteTask(task._id)}
              style={{ marginLeft: "10px" }}
            >
              Delete
            </button>
          </div>
        ))
      )}
    </div>
  );
}

export default TaskList;
